const webhookData = $('Webhook Trigger').first().json;
const b = webhookData.body ?? webhookData;
const run_id = b.run_id || b.runId || b.runID;
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!run_id) {
  return [{ json: { ok: false, run_id: null, error: { code: 'MISSING_FIELDS', message: 'run_id is required' } } }];
}

if (b.workflow_key !== 'watchlist_deep_dive') {
  return [{ json: { ok: false, run_id, error: { code: 'WRONG_WORKFLOW', message: 'workflow_key must be watchlist_deep_dive, got: ' + b.workflow_key } } }];
}

if (!b.org_id || typeof b.org_id !== 'string' || !UUID_RE.test(b.org_id)) {
  return [{ json: { ok: false, run_id, error: { code: 'INVALID_ORG_ID', message: 'org_id must be a valid UUID' } } }];
}

const validDepths = ['light', 'standard'];
const depth = (typeof b.depth === 'string' && validDepths.includes(b.depth)) ? b.depth : 'standard';

return [{ json: { ok: true, run_id, workflow_key: 'watchlist_deep_dive', org_id: b.org_id, org_name: b.org_name || null, website_url: b.website_url || null, depth, triggered_by: b.triggered_by || null } }];

const validated = $('Normalize Input').first().json;
const fetchResult = $('Fetch Org Context').first().json;

let websiteUrl = validated.website_url;

// Try to resolve URL from fetch context if not provided in payload
if (!websiteUrl && Array.isArray(fetchResult) && fetchResult.length > 0) {
  websiteUrl = fetchResult[0].website_url;
} else if (!websiteUrl && fetchResult && fetchResult.website_url) {
  websiteUrl = fetchResult.website_url;
}

if (!websiteUrl || typeof websiteUrl !== 'string' || !websiteUrl.trim()) {
  return [{ json: {
    run_id: validated.run_id,
    org_id: validated.org_id,
    website_url: null,
    crawl_skipped: true,
    skip_reason: 'No website URL available for org',
    watchlist_record: Array.isArray(fetchResult) ? fetchResult[0] || null : fetchResult
  } }];
}

let normalized = websiteUrl.trim();
if (!/^https?:\/\//i.test(normalized)) normalized = 'https://' + normalized;

return [{ json: {
  run_id: validated.run_id,
  org_id: validated.org_id,
  depth: validated.depth,
  website_url: normalized,
  crawl_skipped: false,
  watchlist_record: Array.isArray(fetchResult) ? fetchResult[0] || null : fetchResult
} }];

const resolveData = $('Resolve URL').first().json;
const run_id = resolveData.run_id;
const org_id = resolveData.org_id;

if (resolveData.crawl_skipped) {
  return [{ json: { run_id, org_id, signals: [], signal_count: 0, crawl_skipped: true, skip_reason: resolveData.skip_reason } }];
}

let scrapeData;
try {
  scrapeData = $('Firecrawl Scrape').first().json;
} catch (e) {
  return [{ json: { run_id, org_id, signals: [], signal_count: 0, crawl_error: 'Firecrawl node did not produce output: ' + String(e.message).slice(0, 200) } }];
}

if (scrapeData.error || !scrapeData.success) {
  return [{ json: { run_id, org_id, signals: [], signal_count: 0, crawl_error: String(scrapeData.error || 'Firecrawl returned unsuccessful response').slice(0, 500) } }];
}

const markdown = scrapeData.data?.markdown || scrapeData.markdown || '';
const links = scrapeData.data?.links || scrapeData.links || [];
const metadata = scrapeData.data?.metadata || scrapeData.metadata || {};

const signals = [];
const contentLower = markdown.toLowerCase();

if (markdown.length > 0) {
  signals.push({ signal_type: 'content_size', summary: 'Page content: ' + markdown.length + ' chars, ' + links.length + ' links found', confidence: 1.0, metadata: { char_count: markdown.length, link_count: links.length } });
}

const hiringKeywords = ['hiring', 'careers', 'job openings', 'we are growing', 'join our team', 'open positions'];
const hiringMatches = hiringKeywords.filter(kw => contentLower.includes(kw));
if (hiringMatches.length > 0) {
  signals.push({ signal_type: 'hiring_activity', summary: 'Hiring signals detected: ' + hiringMatches.join(', '), confidence: 0.8, metadata: { matched_keywords: hiringMatches } });
}

const expansionKeywords = ['new location', 'expanding', 'partnership', 'launched', 'announcement', 'press release'];
const expansionMatches = expansionKeywords.filter(kw => contentLower.includes(kw));
if (expansionMatches.length > 0) {
  signals.push({ signal_type: 'expansion_activity', summary: 'Expansion/partnership signals: ' + expansionMatches.join(', '), confidence: 0.7, metadata: { matched_keywords: expansionMatches } });
}

const techKeywords = ['digital equity', 'broadband', 'computer', 'device', 'technology access', 'digital inclusion', 'digital literacy'];
const techMatches = techKeywords.filter(kw => contentLower.includes(kw));
if (techMatches.length > 0) {
  signals.push({ signal_type: 'tech_relevance', summary: 'Digital equity relevance detected: ' + techMatches.join(', '), confidence: 0.85, metadata: { matched_keywords: techMatches } });
}

const fundingKeywords = ['funding', 'grant', 'awarded', 'million', 'investment', 'fundrais'];
const fundingMatches = fundingKeywords.filter(kw => contentLower.includes(kw));
if (fundingMatches.length > 0) {
  signals.push({ signal_type: 'funding_activity', summary: 'Funding/grant signals: ' + fundingMatches.join(', '), confidence: 0.75, metadata: { matched_keywords: fundingMatches } });
}

if (metadata.title || metadata.description) {
  signals.push({ signal_type: 'page_metadata', summary: 'Title: ' + (metadata.title || 'N/A').slice(0, 100), confidence: 1.0, metadata: { title: metadata.title, description: (metadata.description || '').slice(0, 300), source_url: metadata.sourceURL || resolveData.website_url } });
}

return [{ json: { run_id, org_id, signals, signal_count: signals.length, source_url: resolveData.website_url, crawl_error: null } }];

const resolveData = $('Resolve URL').first().json;
return [{ json: {
  run_id: resolveData.run_id,
  org_id: resolveData.org_id,
  signals: [],
  signal_count: 0,
  crawl_skipped: true,
  skip_reason: resolveData.skip_reason || 'No website URL',
  crawl_error: null
} }];

const validated = $('Normalize Input').first().json;
let signalData = null;
let error = null;
let failed_node = null;

// Try to get data from whichever path executed
try {
  signalData = $('Extract Signals').first().json;
} catch (e1) {
  try {
    signalData = $('Skip Crawl').first().json;
  } catch (e2) {
    error = 'Neither Extract Signals nor Skip Crawl produced output';
    failed_node = 'Extract Signals';
  }
}

// CRITICAL FIX: crawl_error from Firecrawl failure is NOT a workflow error.
// The workflow completed successfully — it just couldn't scrape.
// Treat it as 'processed' with zero signals and include the crawl_error as metadata.
let result = null;
if (!error && signalData) {
  result = {
    signals: signalData.signals || [],
    signal_count: signalData.signal_count || 0,
    org_id: signalData.org_id,
    source_url: signalData.source_url || null,
    crawl_skipped: signalData.crawl_skipped || false,
    skip_reason: signalData.skip_reason || null,
    crawl_error: signalData.crawl_error || null
  };
}

// Status is ALWAYS 'processed' unless we had a genuine infrastructure failure
// (node didn't execute at all). Firecrawl failures and missing URLs are valid outcomes.
return [{ json: {
  run_id: validated.run_id,
  workflow_key: 'watchlist_deep_dive',
  status: error ? 'error' : 'processed',
  payload: { result, error, failed_node }
} }];
